package Coding.StringQuestions;

public class ReverseIndividualWords {
    public static void main(String [] args) {
        String sentence = "Java Developer";
        String [] word = sentence.split(" ");
        String reverseSentence= "";
        for(String words : word){
            StringBuilder sb = new StringBuilder(words);
            sb.reverse();
            reverseSentence += sb.toString() + " ";
        }
        System.out.println(reverseSentence.trim());
    }
}

package Coding.StringQuestions;

public class ReverseIndividualWords {
    public static void main(String [] args) {
        String sentence = "Java Developer";
        String [] word = sentence.split(" ");
        String reverseSentence= "";
        for(int i = 0; i < word.length; i++){
            StringBuilder sb = new StringBuilder(word[i]);
            sb.reverse();
            if(i > 0){
                reverseSentence += " ";
            }
            reverseSentence += sb.toString();
        }
        System.out.println(reverseSentence);
    }
}

package HotelBookingAPI;

import java.util.*;

/**
 * Hotel Booking API Response Validation Test Cases
 * Validates that API responses contain correct and complete data
 */
public class ValidateBookingResponse {

    static class BookingResponse {
        String bookingId;
        String hotelName;
        String guestName;
        double totalPrice;
        String checkInDate;
        String checkOutDate;
        int numberOfRooms;
        String confirmationStatus;
        String paymentMethod;

        public BookingResponse(String bookingId, String hotelName, String guestName,
                              double totalPrice, String checkInDate, String checkOutDate,
                              int numberOfRooms, String confirmationStatus, String paymentMethod) {
            this.bookingId = bookingId;
            this.hotelName = hotelName;
            this.guestName = guestName;
            this.totalPrice = totalPrice;
            this.checkInDate = checkInDate;
            this.checkOutDate = checkOutDate;
            this.numberOfRooms = numberOfRooms;
            this.confirmationStatus = confirmationStatus;
            this.paymentMethod = paymentMethod;
        }
    }

    // Test Case 1: Validate Response Contains All Required Fields
    public static void testValidateRequiredFields() {
        System.out.println("\n=== Test Case 1: Validate Response Contains All Required Fields ===");

        BookingResponse response = new BookingResponse("BK20260619001", "Grand Plaza", "John Doe",
                                                       450.0, "2026-06-25", "2026-06-28", 1,
                                                       "CONFIRMED", "CREDIT_CARD");

        boolean bookingIdPresent = response.bookingId != null && !response.bookingId.isEmpty();
        boolean hotelNamePresent = response.hotelName != null && !response.hotelName.isEmpty();
        boolean guestNamePresent = response.guestName != null && !response.guestName.isEmpty();
        boolean pricePresent = response.totalPrice > 0;
        boolean confirmationStatusPresent = response.confirmationStatus != null && !response.confirmationStatus.isEmpty();

        System.out.println("Required Fields Validation:");
        System.out.println("  - Booking ID: " + (bookingIdPresent ? "PASS" : "FAIL"));
        System.out.println("  - Hotel Name: " + (hotelNamePresent ? "PASS" : "FAIL"));
        System.out.println("  - Guest Name: " + (guestNamePresent ? "PASS" : "FAIL"));
        System.out.println("  - Total Price: " + (pricePresent ? "PASS" : "FAIL"));
        System.out.println("  - Confirmation Status: " + (confirmationStatusPresent ? "PASS" : "FAIL"));

        boolean allFieldsPresent = bookingIdPresent && hotelNamePresent && guestNamePresent &&
                                  pricePresent && confirmationStatusPresent;
        System.out.println("\nOverall Result: " + (allFieldsPresent ? "PASS" : "FAIL"));
    }

    // Test Case 2: Validate Price Calculation
    public static void testValidatePriceCalculation() {
        System.out.println("\n=== Test Case 2: Validate Price Calculation in Response ===");

        BookingResponse response = new BookingResponse("BK001", "Grand Plaza", "John Doe",
                                                       900.0, "2026-06-25", "2026-06-28", 2,
                                                       "CONFIRMED", "CREDIT_CARD");

        double pricePerNight = 150.0;
        int nights = 3;
        int rooms = 2;
        double expectedPrice = pricePerNight * nights * rooms;

        System.out.println("Price Calculation Details:");
        System.out.println("  - Price per Night: $" + pricePerNight);
        System.out.println("  - Number of Nights: " + nights);
        System.out.println("  - Number of Rooms: " + rooms);
        System.out.println("  - Expected Total: $" + expectedPrice);
        System.out.println("  - Actual Total in Response: $" + response.totalPrice);
        System.out.println("  - Result: " + (response.totalPrice == expectedPrice ? "PASS" : "FAIL"));
    }

    // Test Case 3: Validate Confirmation Status Values
    public static void testValidateConfirmationStatus() {
        System.out.println("\n=== Test Case 3: Validate Confirmation Status Values ===");

        List<String> validStatuses = Arrays.asList("CONFIRMED", "PENDING", "CANCELLED");
        List<BookingResponse> responses = new ArrayList<>();

        responses.add(new BookingResponse("BK001", "Grand Plaza", "John Doe", 450.0,
                                         "2026-06-25", "2026-06-28", 1, "CONFIRMED", "CREDIT_CARD"));
        responses.add(new BookingResponse("BK002", "Beach Resort", "Jane Doe", 600.0,
                                         "2026-07-01", "2026-07-05", 1, "PENDING", "DEBIT_CARD"));
        responses.add(new BookingResponse("BK003", "Mountain Lodge", "Bob Smith", 270.0,
                                         "2026-08-10", "2026-08-12", 1, "CANCELLED", "PAYPAL"));
        responses.add(new BookingResponse("BK004", "City View", "Alice Brown", 480.0,
                                         "2026-09-01", "2026-09-03", 1, "INVALID_STATUS", "CREDIT_CARD"));

        System.out.println("Validating " + responses.size() + " booking responses:\n");

        int validCount = 0;
        for (BookingResponse response : responses) {
            boolean isValid = validStatuses.contains(response.confirmationStatus);
            String result = isValid ? "PASS" : "FAIL";
            System.out.println("  - Booking " + response.bookingId + " Status: " +
                             response.confirmationStatus + " (" + result + ")");
            if (isValid) validCount++;
        }

        System.out.println("\nValid Responses: " + validCount + "/4");
        System.out.println("Expected: 3 valid, 1 invalid");
        System.out.println("Result: " + (validCount == 3 ? "PASS" : "FAIL"));
    }

    // Test Case 4: Compare Expected vs Actual Response
    public static void testCompareExpectedVsActualResponse() {
        System.out.println("\n=== Test Case 4: Compare Expected vs Actual Response ===");

        BookingResponse expectedResponse = new BookingResponse("BK001", "Grand Plaza", "John Doe",
                                                               450.0, "2026-06-25", "2026-06-28", 1,
                                                               "CONFIRMED", "CREDIT_CARD");

        BookingResponse actualResponse = new BookingResponse("BK001", "Grand Plaza", "John Doe",
                                                             450.0, "2026-06-25", "2026-06-28", 1,
                                                             "CONFIRMED", "CREDIT_CARD");

        System.out.println("Field Comparison:");
        System.out.println("  - Booking ID: Expected=" + expectedResponse.bookingId +
                          ", Actual=" + actualResponse.bookingId +
                          " (" + (expectedResponse.bookingId.equals(actualResponse.bookingId) ? "PASS" : "FAIL") + ")");
        System.out.println("  - Hotel Name: Expected=" + expectedResponse.hotelName +
                          ", Actual=" + actualResponse.hotelName +
                          " (" + (expectedResponse.hotelName.equals(actualResponse.hotelName) ? "PASS" : "FAIL") + ")");
        System.out.println("  - Guest Name: Expected=" + expectedResponse.guestName +
                          ", Actual=" + actualResponse.guestName +
                          " (" + (expectedResponse.guestName.equals(actualResponse.guestName) ? "PASS" : "FAIL") + ")");
        System.out.println("  - Total Price: Expected=$" + expectedResponse.totalPrice +
                          ", Actual=$" + actualResponse.totalPrice +
                          " (" + (expectedResponse.totalPrice == actualResponse.totalPrice ? "PASS" : "FAIL") + ")");
        System.out.println("  - Check-in Date: Expected=" + expectedResponse.checkInDate +
                          ", Actual=" + actualResponse.checkInDate +
                          " (" + (expectedResponse.checkInDate.equals(actualResponse.checkInDate) ? "PASS" : "FAIL") + ")");
        System.out.println("  - Check-out Date: Expected=" + expectedResponse.checkOutDate +
                          ", Actual=" + actualResponse.checkOutDate +
                          " (" + (expectedResponse.checkOutDate.equals(actualResponse.checkOutDate) ? "PASS" : "FAIL") + ")");
        System.out.println("  - Confirmation Status: Expected=" + expectedResponse.confirmationStatus +
                          ", Actual=" + actualResponse.confirmationStatus +
                          " (" + (expectedResponse.confirmationStatus.equals(actualResponse.confirmationStatus) ? "PASS" : "FAIL") + ")");
    }

    // Test Case 5: Validate Field Data Types
    public static void testValidateFieldDataTypes() {
        System.out.println("\n=== Test Case 5: Validate Field Data Types ===");

        BookingResponse response = new BookingResponse("BK001", "Grand Plaza", "John Doe",
                                                       450.0, "2026-06-25", "2026-06-28", 1,
                                                       "CONFIRMED", "CREDIT_CARD");

        System.out.println("Field Data Type Validation:");
        System.out.println("  - Booking ID is String: " + (response.bookingId instanceof String ? "PASS" : "FAIL"));
        System.out.println("  - Hotel Name is String: " + (response.hotelName instanceof String ? "PASS" : "FAIL"));
        System.out.println("  - Guest Name is String: " + (response.guestName instanceof String ? "PASS" : "FAIL"));
        System.out.println("  - Total Price is Double: " + (response.totalPrice instanceof Double ? "PASS" : "FAIL"));
        System.out.println("  - Check-in Date is String: " + (response.checkInDate instanceof String ? "PASS" : "FAIL"));
        System.out.println("  - Check-out Date is String: " + (response.checkOutDate instanceof String ? "PASS" : "FAIL"));
        System.out.println("  - Number of Rooms is Integer: " + (response.numberOfRooms instanceof Integer ? "PASS" : "FAIL"));
        System.out.println("  - Confirmation Status is String: " + (response.confirmationStatus instanceof String ? "PASS" : "FAIL"));
    }

    // Test Case 6: Validate Date Format
    public static void testValidateDateFormat() {
        System.out.println("\n=== Test Case 6: Validate Date Format ===");

        List<BookingResponse> responses = new ArrayList<>();
        responses.add(new BookingResponse("BK001", "Grand Plaza", "John Doe", 450.0,
                                         "2026-06-25", "2026-06-28", 1, "CONFIRMED", "CREDIT_CARD"));
        responses.add(new BookingResponse("BK002", "Beach Resort", "Jane Doe", 600.0,
                                         "25-06-2026", "28-06-2026", 1, "CONFIRMED", "CREDIT_CARD"));
        responses.add(new BookingResponse("BK003", "Mountain Lodge", "Bob Smith", 270.0,
                                         "2026/06/25", "2026/06/28", 1, "CONFIRMED", "CREDIT_CARD"));

        String validDatePattern = "\\d{4}-\\d{2}-\\d{2}";

        System.out.println("Date Format Validation (Expected: YYYY-MM-DD):\n");

        int validDates = 0;
        for (BookingResponse response : responses) {
            boolean checkInValid = response.checkInDate.matches(validDatePattern);
            boolean checkOutValid = response.checkOutDate.matches(validDatePattern);
            boolean bothValid = checkInValid && checkOutValid;

            String result = bothValid ? "PASS" : "FAIL";
            System.out.println("  - Booking " + response.bookingId + ":");
            System.out.println("      Check-in: " + response.checkInDate + " (" +
                             (checkInValid ? "PASS" : "FAIL") + ")");
            System.out.println("      Check-out: " + response.checkOutDate + " (" +
                             (checkOutValid ? "PASS" : "FAIL") + ")");

            if (bothValid) validDates++;
        }

        System.out.println("\nValid Dates: " + validDates + "/3");
        System.out.println("Expected: 1 valid (only BK001)");
        System.out.println("Result: " + (validDates == 1 ? "PASS" : "FAIL"));
    }

    // Test Case 7: Validate Response Completeness
    public static void testValidateResponseCompleteness() {
        System.out.println("\n=== Test Case 7: Validate Response Completeness ===");

        BookingResponse completeResponse = new BookingResponse("BK001", "Grand Plaza", "John Doe",
                                                               450.0, "2026-06-25", "2026-06-28", 1,
                                                               "CONFIRMED", "CREDIT_CARD");

        BookingResponse incompleteResponse = new BookingResponse("BK002", "", null,
                                                                 0, "", "", 0, "", null);

        System.out.println("Response 1 (Complete):");
        System.out.println("  - Booking ID: " + (completeResponse.bookingId != null && !completeResponse.bookingId.isEmpty() ? "✓" : "✗"));
        System.out.println("  - Hotel Name: " + (completeResponse.hotelName != null && !completeResponse.hotelName.isEmpty() ? "✓" : "✗"));
        System.out.println("  - Guest Name: " + (completeResponse.guestName != null && !completeResponse.guestName.isEmpty() ? "✓" : "✗"));
        System.out.println("  - Total Price: " + (completeResponse.totalPrice > 0 ? "✓" : "✗"));
        System.out.println("  - Check-in: " + (!completeResponse.checkInDate.isEmpty() ? "✓" : "✗"));
        System.out.println("  - Result: PASS");

        System.out.println("\nResponse 2 (Incomplete):");
        System.out.println("  - Booking ID: " + (incompleteResponse.bookingId != null && !incompleteResponse.bookingId.isEmpty() ? "✓" : "✗"));
        System.out.println("  - Hotel Name: " + (incompleteResponse.hotelName != null && !incompleteResponse.hotelName.isEmpty() ? "✓" : "✗"));
        System.out.println("  - Guest Name: " + (incompleteResponse.guestName != null && !incompleteResponse.guestName.isEmpty() ? "✓" : "✗"));
        System.out.println("  - Total Price: " + (incompleteResponse.totalPrice > 0 ? "✓" : "✗"));
        System.out.println("  - Check-in: " + (!incompleteResponse.checkInDate.isEmpty() ? "✓" : "✗"));
        System.out.println("  - Result: FAIL");
    }

    public static void main(String[] args) {
        System.out.println("████████████████████████████████████████████");
        System.out.println("BOOKING RESPONSE VALIDATION TEST CASES");
        System.out.println("████████████████████████████████████████████");

        testValidateRequiredFields();
        testValidatePriceCalculation();
        testValidateConfirmationStatus();
        testCompareExpectedVsActualResponse();
        testValidateFieldDataTypes();
        testValidateDateFormat();
        testValidateResponseCompleteness();

        System.out.println("\n████████████████████████████████████████████");
        System.out.println("TEST EXECUTION COMPLETED");
        System.out.println("████████████████████████████████████████████");
    }
}

